/* ccinfo.nl analyse-archief widget v1.3 - extern (GitHub Pages) - 2026-06-23 */
(function(){
  if (window.location.pathname.indexOf('/analyse') !== 0) return;
  if (document.getElementById('ccinfo-archief')) return;
  function _d(b){return new TextDecoder().decode(Uint8Array.from(atob(b),function(c){return c.charCodeAt(0);}));}
  var introHtml   = _d('');
  var archiefHtml = _d('');
  var footerHtml  = _d('');
  function inject() {
    if (document.getElementById('ccinfo-archief')) return;
    // Intro: voor het eerste form-element op de pagina
    var form = document.querySelector('form');
    if (form && !document.getElementById('ccinfo-analyse-intro')) {
      var introBlok = document.createElement('div');
      introBlok.innerHTML = introHtml;
      form.parentNode.insertBefore(introBlok, form);
    }
    // Archief + footer: na de sectie-content
    var target = document.querySelector('.jw-section-content');
    if (!target) target = document.querySelector('.jw-section');
    if (target) {
      var archiefBlok = document.createElement('div');
      archiefBlok.innerHTML = archiefHtml + footerHtml;
      target.appendChild(archiefBlok);
    }
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', inject);
  } else {
    inject();
  }
})();
